// Render een A4 HTML-cheatsheet met woning- en kijkerinfo plus ruime
// aantekenvlakken die 1-op-1 mappen op de Mautic-velden die
// POST /api/agenda/[id]/cheatsheet/verwerk verwacht.
// De HTML wordt als binary 'data' (index.html) doorgegeven aan Gotenberg.
const ctx = $input.first().json;
const a = ctx.afspraak || {};
const k = ctx.kijker || {};
const w = ctx.woning || {};
const ai = k.aiAnalyse || {};
const kw = k.kwalificatie || {};
const bz = k.bezichtiging || {};

const esc = (v) => (v === null || v === undefined ? '' : String(v)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'));
const jaNee = (v) => (v === true ? 'Ja' : v === false ? 'Nee' : '-');
const beginISO = a.begin || '';
const beginNL = a.beginLokaal?.label || (beginISO ? new Date(beginISO).toLocaleString('nl-NL', { timeZone: 'Europe/Amsterdam', weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' }) : '');
const prijs = w.prijs && w.prijs.koopsom ? ('\u20ac ' + Number(w.prijs.koopsom).toLocaleString('nl-NL')) : (w.prijs && w.prijs.koopprijsLabel) || '';

const html = `<!DOCTYPE html><html lang="nl"><head><meta charset="utf-8"><style>
  @page { size: A4; margin: 16mm; }
  body{font-family:system-ui,Arial,sans-serif;color:#1f2937;font-size:12px;line-height:1.45}
  h1{font-size:19px;margin:0 0 2px}
  h2{font-size:13px;border-bottom:1px solid #e5e7eb;padding-bottom:3px;margin:16px 0 6px;color:#0f172a}
  .sub{color:#64748b;margin-bottom:10px}
  .grid{display:grid;grid-template-columns:1fr 1fr;gap:4px 18px}
  .row{display:flex;gap:6px}
  .lab{font-weight:600;color:#475569;min-width:130px}
  .foto{float:right;width:180px;height:120px;object-fit:cover;border-radius:8px;margin:0 0 8px 12px}
  .vak{border:1px solid #cbd5e1;border-radius:6px;min-height:64px;margin:4px 0 10px;padding:6px}
  .vaklabel{font-weight:600;font-size:11px;color:#475569;margin-top:8px}
  .pill{display:inline-block;background:#eff6ff;color:#1d4ed8;border-radius:999px;padding:1px 8px;font-size:11px}
</style></head><body>
  ${w.foto ? `<img class="foto" src="${esc(w.foto)}"/>` : ''}
  <h1>Bezichtiging \u2014 ${esc(a.contactNaam || k.naam || '')}</h1>
  <div class="sub">${esc(w.titel || '')}${w.adres ? ' \u00b7 ' + esc(w.adres) : ''}<br/>${esc(beginNL)}${a.medewerker ? ' \u00b7 ' + esc(a.medewerker) : ''}</div>

  <h2>Woning</h2>
  <div class="grid">
    <div class="row"><span class="lab">Vraagprijs</span><span>${esc(prijs)}</span></div>
    <div class="row"><span class="lab">Woonoppervlak</span><span>${esc(w.kenmerken?.woonoppervlakte || '')} m\u00b2</span></div>
    <div class="row"><span class="lab">Kamers</span><span>${esc(w.kenmerken?.kamers || '')}</span></div>
    <div class="row"><span class="lab">Bouwjaar</span><span>${esc(w.kenmerken?.bouwjaar || '')}</span></div>
    <div class="row"><span class="lab">Energieklasse</span><span>${esc(w.kenmerken?.energieklasse || '')}</span></div>
  </div>

  <h2>Kijker</h2>
  <div class="grid">
    <div class="row"><span class="lab">Telefoon</span><span>${esc(k.telefoon || a.contactTelefoon || '')}</span></div>
    <div class="row"><span class="lab">E-mail</span><span>${esc(k.email || a.contactEmail || '')}</span></div>
    <div class="row"><span class="lab">Eigen woning</span><span>${jaNee(kw.heeftEigenWoning)}</span></div>
    <div class="row"><span class="lab">Overweegt verkoop</span><span>${jaNee(kw.overwegtVerkoop)}</span></div>
    <div class="row"><span class="lab">Hypotheekstatus</span><span>${esc(kw.hypotheekStatus || '')}</span></div>
    <div class="row"><span class="lab">Eerdere interesse</span><span>${bz.interesseScore != null ? esc(bz.interesseScore) + '/100' : '-'}</span></div>
  </div>
  ${(ai.huidigeSituatie || ai.woningMotivatie || ai.budgetIndicatie || ai.tijdlijn) ? `<div style="margin-top:6px">
    ${ai.huidigeSituatie ? `<div class="row"><span class="lab">Situatie</span><span>${esc(ai.huidigeSituatie)}</span></div>` : ''}
    ${ai.woningMotivatie ? `<div class="row"><span class="lab">Motivatie</span><span>${esc(ai.woningMotivatie)}</span></div>` : ''}
    ${ai.budgetIndicatie ? `<div class="row"><span class="lab">Budget</span><span>${esc(ai.budgetIndicatie)}</span></div>` : ''}
    ${ai.tijdlijn ? `<div class="row"><span class="lab">Tijdlijn</span><span>${esc(ai.tijdlijn)}</span></div>` : ''}
  </div>` : ''}

  <h2>Aantekeningen (worden via OCR teruggelezen naar Mautic)</h2>
  <div class="vaklabel">Notities bezichtiging</div><div class="vak"></div>
  <div class="vaklabel">Interesse 0\u2013100</div><div class="vak"></div>
  <div class="vaklabel">Verkoopgesprek-status</div><div class="vak"></div>
  <div class="vaklabel">Vervolgactie</div><div class="vak"></div>
</body></html>`;

const slug = (a.contactNaam || k.naam || 'kijker').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
const datum = a.beginLokaal?.bestandsDatum || (beginISO ? new Date(beginISO).toLocaleDateString('en-CA', { timeZone: 'Europe/Amsterdam' }) : 'onbekend');
const map = String(ctx.project?.realworksId || ctx.project?.naam || 'overig').replace(/[^A-Za-z0-9_-]+/g, '_');
const basePath = $env.NEXTCLOUD_BASE_PATH || 'Bezichtigingen';
const bestandsnaam = `bezichtiging_${datum}_${slug}_${a.id}.pdf`;
const pad = `${basePath}/${map}/${bestandsnaam}`;

return [{
  json: { afspraakId: a.id, pad, map, basePath, bestandsnaam, contactNaam: a.contactNaam || k.naam || '' },
  binary: { data: { data: Buffer.from(html).toString('base64'), mimeType: 'text/html', fileName: 'index.html' } }
}];
